// â”€â”€ WAProjectHomeView â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// PostHog AI-first project homepage with Max AI chat, search, pinned/recent/starred.
// Connects to self-hosted PostHog via src/api/posthog.ts

// â”€â”€ Minimal markdown renderer (bold, inline code, links) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function renderHomeMarkdown(text: string): React.ReactNode[] {
  const lines = text.split('\n');
  return lines.map((line, li) => {
    const parts: React.ReactNode[] = [];
    let i = 0;
    let key = 0;
    while (i < line.length) {
      // Bold **text**
      if (line[i] === '*' && line[i+1] === '*') {
        const end = line.indexOf('**', i + 2);
        if (end !== -1) {
          parts.push(<strong key={key++}>{line.slice(i + 2, end)}</strong>);
          i = end + 2; continue;
        }
      }
      // Inline code `text`
      if (line[i] === '`') {
        const end = line.indexOf('`', i + 1);
        if (end !== -1) {
          parts.push(<code key={key++} className="bg-[#f3f3f1] text-[#e8572a] px-1 rounded text-xs font-mono">{line.slice(i + 1, end)}</code>);
          i = end + 1; continue;
        }
      }
      // Find next special char
      let next = line.length;
      for (const ch of ['**', '`']) {
        const idx = line.indexOf(ch, i);
        if (idx !== -1 && idx < next) next = idx;
      }
      parts.push(<span key={key++}>{line.slice(i, next)}</span>);
      i = next;
    }
    return (
      <React.Fragment key={li}>
        {parts}
        {li < lines.length - 1 && <br />}
      </React.Fragment>
    );
  });
}

// â”€â”€ Types â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
interface HomeMessage {
  role: 'user' | 'assistant' | 'thinking';
  content: string;
  status: 'loading' | 'done' | 'error';
}

interface PinnedItem {
  id: number | string;
  name: string;
  type: 'dashboard' | 'insight';
}

interface RecentItem {
  id: number | string;
  name: string;
  type: 'dashboard' | 'insight' | 'feature_flag' | 'survey' | 'experiment' | 'notebook';
  short_id?: string;
}

type HomeMode = 'idle' | 'ai' | 'search';

// ── Cross-screen navigation helper ────────────────────────────────────────────
// Lets any view request opening another view with optional intent (e.g. open
// a specific dashboard / insight / recording). The destination view reads the
// intent from localStorage on mount and clears it.
type WANavTarget =
  | 'appDashboards' | 'appProductAnalytics' | 'appSqlEditor' | 'appWebAnalytics'
  | 'appLlmAnalytics' | 'appClusters' | 'appPlayground'
  | 'appErrorTracking' | 'appHeatmaps' | 'appLogs' | 'appSessionReplay' | 'appSupport' | 'appSurveys'
  | 'appEarlyAccess' | 'appExperiments' | 'appFeatureFlags'
  | 'appNotebooks' | 'appToolbar' | 'appWebScripts' | 'appWorkflows';
function navigateWA(appsSub: WANavTarget, intent?: { kind: string; id: any; data?: any }) {
  if (intent) {
    try { localStorage.setItem(`wa-nav-${intent.kind}`, JSON.stringify({ id: intent.id, data: intent.data, ts: Date.now() })); } catch {}
  }
  window.dispatchEvent(new CustomEvent('wa-navigate', { detail: { appsSub } }));
}
function consumeNavIntent<T = any>(kind: string): { id: T; data?: any } | null {
  try {
    const raw = localStorage.getItem(`wa-nav-${kind}`);
    if (!raw) return null;
    localStorage.removeItem(`wa-nav-${kind}`);
    const parsed = JSON.parse(raw);
    // Ignore stale intents older than 5 seconds (likely from a previous mount)
    if (Date.now() - (parsed.ts ?? 0) > 5000) return null;
    return { id: parsed.id, data: parsed.data };
  } catch { return null; }
}

// â”€â”€ Icon helpers â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function ItemTypeIcon({ type }: { type: RecentItem['type'] }) {
  const cls = 'w-4 h-4 flex-shrink-0';
  switch (type) {
    case 'dashboard':
      return <svg viewBox="0 0 16 16" className={cls}><rect x="1.5" y="1.5" width="5.5" height="5.5" rx="1" fill="#3b59f6" opacity=".8"/><rect x="9" y="1.5" width="5.5" height="5.5" rx="1" fill="#3b59f6" opacity=".5"/><rect x="1.5" y="9" width="5.5" height="5.5" rx="1" fill="#3b59f6" opacity=".5"/><rect x="9" y="9" width="5.5" height="5.5" rx="1" fill="#3b59f6" opacity=".3"/></svg>;
    case 'insight':
      return <svg viewBox="0 0 16 16" className={cls}><path d="M1 13l3-4 3 2 3-5 3 3" stroke="#3b59f6" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>;
    case 'feature_flag':
      return <svg viewBox="0 0 16 16" className={cls}><path d="M3 2v12M3 2l9 4-9 4" stroke="#e8572a" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>;
    case 'survey':
      return <svg viewBox="0 0 16 16" className={cls}><rect x="2" y="1.5" width="12" height="13" rx="2" fill="none" stroke="#646462" strokeWidth="1.3"/><path d="M5 5.5h6M5 8h6M5 10.5h3.5" stroke="#646462" strokeWidth="1.1" strokeLinecap="round"/></svg>;
    case 'experiment':
      return <svg viewBox="0 0 16 16" className={cls}><path d="M6 1v5.5L2.5 13.5h11L10 6.5V1" stroke="#646462" strokeWidth="1.3" fill="none" strokeLinecap="round" strokeLinejoin="round"/><path d="M4.5 1h7" stroke="#646462" strokeWidth="1.3" strokeLinecap="round"/></svg>;
    case 'notebook':
      return <svg viewBox="0 0 16 16" className={cls}><rect x="3" y="1" width="10" height="14" rx="1.5" fill="none" stroke="#646462" strokeWidth="1.3"/><path d="M6 5h5M6 8h5M6 11h3" stroke="#646462" strokeWidth="1.1" strokeLinecap="round"/></svg>;
    default:
      return <svg viewBox="0 0 16 16" className={cls}><circle cx="8" cy="8" r="5.5" fill="none" stroke="#646462" strokeWidth="1.3"/></svg>;
  }
}
type SearchCategory = 'all' | 'recent' | 'pinned' | 'events' | 'actions' | 'insights' | 'dashboards' | 'notebooks' | 'issues';

