const THINKING_MSGS = [
  'Pensando...', 'Analizando tus datos...', 'Discombobulating...', 'Dame un momento...',
  'Consultando métricas...', 'Procesando...', 'Cogitating...', 'Racionalizando...',
  'Investigando...', 'Computando respuesta...', 'Deliberating...', 'Hmm...',
];

function WAProjectHomeView() {
  const [mode, setMode]               = React.useState<HomeMode>('idle');
  const [query, setQuery]             = React.useState('');
  const [messages, setMessages]       = React.useState<HomeMessage[]>([]);
  const [conversationId, setConvId]   = React.useState<string | null>(null);
  const [isStreaming, setIsStreaming]  = React.useState(false);
  const [thinkingMsg, setThinkingMsg] = React.useState('Pensando...');
  const [searchResults, setSearchRes] = React.useState<RecentItem[]>([]);
  const [searchLoading, setSearchLoading] = React.useState(false);
  const [convTitle, setConvTitle]     = React.useState('');

  // Context selector
  const [agentMode, setAgentMode]     = React.useState<AgentMode>('auto');
  const [showModeMenu, setShowModeMenu] = React.useState(false);
  const modeMenuRef = React.useRef<HTMLDivElement>(null);

  // Message UI state
  const [expandedThoughts, setExpandedThoughts] = React.useState<Set<number>>(new Set());
  const [msgFeedback, setMsgFeedback] = React.useState<Record<number, 'up' | 'down'>>({});
  const [copiedMsg, setCopiedMsg]     = React.useState<number | null>(null);

  // Search state
  const [searchCategory, setSearchCategory] = React.useState<SearchCategory>('all');
  const [searchCounts, setSearchCounts]     = React.useState<Record<string, number>>({ recent: 0, pinned: 0, events: 0, actions: 0, insights: 0, dashboards: 0, notebooks: 0, issues: 0 });

  // Data from PostHog
  const [username, setUsername]       = React.useState('');
  const [pinned, setPinned]           = React.useState<PinnedItem[]>([]);
  const [recents, setRecents]         = React.useState<RecentItem[]>([]);
  const [starred, setStarred]         = React.useState<PinnedItem[]>([]);
  const [dataLoading, setDataLoading] = React.useState(true);

  const inputRef     = React.useRef<HTMLTextAreaElement>(null);
  const chatBottomRef = React.useRef<HTMLDivElement>(null);
  const abortRef     = React.useRef<AbortController | null>(null);
  const searchTimeout = React.useRef<ReturnType<typeof setTimeout> | null>(null);

  // ── Reusable Activity components state ─────────────────────────────────────
  const [showQuickStart, setShowQuickStart] = React.useState(false);
  const [showConfig,     setShowConfig]     = React.useState(false);
  const [selectedEvent,  setSelectedEvent]  = React.useState<any>(null);
  const [recentEvents,   setRecentEvents]   = React.useState<any[]>([]);
  const [eventsLoading,  setEventsLoading]  = React.useState(false);

  // Widget visibility (persisted in localStorage)
  const DEFAULT_WIDGETS = { pinned: true, recents: true, starred: true, activity: true };
  const [widgets, setWidgets] = React.useState<{ pinned: boolean; recents: boolean; starred: boolean; activity: boolean }>(DEFAULT_WIDGETS);
  React.useEffect(() => {
    try {
      const raw = localStorage.getItem('wa-home-widgets');
      if (raw) setWidgets({ ...DEFAULT_WIDGETS, ...JSON.parse(raw) });
    } catch {}
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  React.useEffect(() => {
    try { localStorage.setItem('wa-home-widgets', JSON.stringify(widgets)); } catch {}
  }, [widgets]);

  // ── Load recent activity (last 5 events) ────────────────────────────────────
  React.useEffect(() => {
    if (!widgets.activity) return;
    let cancelled = false;
    setEventsLoading(true);
    (async () => {
      try {
        const ph = await import('../../api/posthog');
        if (!ph.getTeamId()) await ph.bootstrapPostHog();
        const res: any = await ph.posthog.events.query({
          query: {
            kind: 'EventsQuery',
            select: ['*', 'event', 'person', 'properties.$current_url', 'properties.$lib', 'timestamp'],
            orderBy: ['timestamp DESC'],
            after: '-1h',
            limit: 5,
          },
        });
        if (cancelled) return;
        const rows = (res.results ?? []).map((r: any[]) => {
          const obj = r[0] || {};
          return {
            uuid: obj.uuid, event: obj.event, distinct_id: obj.distinct_id,
            timestamp: obj.timestamp, properties: obj.properties ?? {}, person: obj.person ?? null,
          };
        });
        setRecentEvents(rows);
      } catch { /* silent */ }
      finally { if (!cancelled) setEventsLoading(false); }
    })();
    return () => { cancelled = true; };
  }, [widgets.activity]);

  // â”€â”€ Bootstrap: load user + PostHog data â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  React.useEffect(() => {
    let cancelled = false;

    async function load() {
      try {
        // Lazy-import to avoid circular deps at module level
        const ph = await import('../../api/posthog');

        // Bootstrap if not already done
        if (!ph.getTeamId()) {
          await ph.bootstrapPostHog();
        }

        if (cancelled) return;

        const user = ph.getCurrentUser();
        if (user) {
          setUsername(user.first_name || user.email?.split('@')[0] || 'Usuario');
        }

        const projectId = ph.getProjectId();
        const teamId    = ph.getTeamId();
        if (!projectId || !teamId) { setDataLoading(false); return; }

        // Pinned dashboards
        ph.phGet(`/api/projects/${projectId}/dashboards/`, { pinned: true, limit: 6 })
          .then((res: any) => {
            if (!cancelled) setPinned((res.results ?? []).map((d: any) => ({ id: d.id, name: d.name, type: 'dashboard' as const })));
          }).catch(() => {});

        // Recent insights
        ph.phGet(`/api/environments/${teamId}/insights/`, { saved: true, order: '-last_viewed_at', limit: 6 })
          .then((res: any) => {
            if (!cancelled) setRecents((res.results ?? []).map((i: any) => ({ id: i.id, name: i.name || i.derived_name || 'Sin nombre', type: 'insight' as const })));
          }).catch(() => {});

        // Starred dashboards (use bookmarked = true)
        ph.phGet(`/api/projects/${projectId}/dashboards/`, { limit: 6 })
          .then((res: any) => {
            if (!cancelled) {
              const bookmarked = (res.results ?? []).filter((d: any) => d.is_shared || d.starred);
              setStarred(bookmarked.map((d: any) => ({ id: d.id, name: d.name, type: 'dashboard' as const })));
            }
          }).catch(() => {});

      } catch (err) {
        console.warn('[WAProjectHome] PostHog load error:', err);
      } finally {
        if (!cancelled) setDataLoading(false);
      }
    }

    load();
    return () => { cancelled = true; };
  }, []);

  // â”€â”€ Focus input on idle â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  React.useEffect(() => {
    if (mode === 'idle') {
      const t = setTimeout(() => inputRef.current?.focus(), 120);
      return () => clearTimeout(t);
    }
  }, [mode]);

  // â”€â”€ Auto-scroll chat â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  React.useEffect(() => {
    chatBottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // â”€â”€ Search â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const runSearch = React.useCallback(async (q: string) => {
    if (!q.trim()) { setSearchRes([]); return; }
    setSearchLoading(true);
    try {
      const ph = await import('../../api/posthog');
      const projectId = ph.getProjectId();
      if (!projectId) return;
      const res: any = await ph.phGet(`/api/projects/${projectId}/search/`, { q, limit: 10 });
      const items: RecentItem[] = (res.results ?? []).map((r: any) => ({
        id: r.result_id,
        name: r.name || r.derived_name || r.key || 'Sin nombre',
        type: (r.type === 'dashboard' ? 'dashboard'
          : r.type === 'insight'   ? 'insight'
          : r.type === 'feature_flag' ? 'feature_flag'
          : r.type === 'survey'    ? 'survey'
          : r.type === 'experiment'? 'experiment'
          : r.type === 'notebook'  ? 'notebook'
          : 'insight') as RecentItem['type'],
      }));
      setSearchRes(items);
    } catch { setSearchRes([]); }
    finally { setSearchLoading(false); }
  }, []);

  // â”€â”€ Send message to Max AI â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const sendMessage = React.useCallback(async (text: string) => {
    if (!text.trim() || isStreaming) return;

    setMode('ai');
    setIsStreaming(true);
    // Generate conversation title from first message
    if (messages.length === 0) {
      setConvTitle(text.length > 60 ? text.slice(0, 57) + '...' : text);
    }
    setThinkingMsg(THINKING_MSGS[Math.floor(Math.random() * THINKING_MSGS.length)]);

    // Add user message immediately
    setMessages(prev => [...prev, { role: 'user', content: text, status: 'done' }]);

    // Add placeholder assistant message
    setMessages(prev => [...prev, { role: 'thinking', content: '', status: 'loading' }]);

    let accContent = '';
    let gotFirstChunk = false;
    const abort = new AbortController();
    abortRef.current = abort;

    try {
      const ph = await import('../../api/posthog');
      if (!ph.getTeamId()) await ph.bootstrapPostHog();

      await ph.phStream(
        `/api/environments/${ph.getTeamId()}/conversations/`,
        {
          content:      text,
          conversation: conversationId ?? undefined,
          trace_id:     crypto.randomUUID(),
          agent_mode:   agentMode !== 'auto' ? agentMode : undefined,
        },
        (event) => {
          if (abort.signal.aborted) return;

          // Conversation created / updated
          if (event.type === 'conversation' && event.data?.id) {
            setConvId(event.data.id);
          }

          // AI message (complete or chunk)
          if (event.type === 'message' || event.type === 'ai_message') {
            const msg = event.data;
            if (msg?.type === 'ai' && typeof msg.content === 'string') {
              accContent = msg.content;
              gotFirstChunk = true;
              setMessages(prev => {
                const next = [...prev];
                const last = next[next.length - 1];
                if (last?.role === 'thinking' || last?.role === 'assistant') {
                  next[next.length - 1] = { role: 'assistant', content: accContent, status: 'loading' };
                } else {
                  next.push({ role: 'assistant', content: accContent, status: 'loading' });
                }
                return next;
              });
            }
          }

          // Status events (thinking, generating, etc.)
          if (event.type === 'status' && event.data?.status) {
            const s = event.data.status;
            if (s === 'thinking') setThinkingMsg('Analizando tus datos...');
            if (s === 'generating') setThinkingMsg('Escribiendo respuesta...');
          }

          // Streaming text chunks
          if (event.type === 'ai_message_chunk' && typeof event.data?.content === 'string') {
            accContent += event.data.content;
            gotFirstChunk = true;
            setMessages(prev => {
              const next = [...prev];
              const last = next[next.length - 1];
              if (last?.role === 'thinking' || last?.role === 'assistant') {
                next[next.length - 1] = { role: 'assistant', content: accContent, status: 'loading' };
              } else {
                next.push({ role: 'assistant', content: accContent, status: 'loading' });
              }
              return next;
            });
          }
        },
        abort.signal,
      );

      // Finalize
      setMessages(prev => {
        const next = [...prev];
        const last = next[next.length - 1];
        if (last && (last.role === 'assistant' || last.role === 'thinking')) {
          next[next.length - 1] = {
            role: 'assistant',
            content: gotFirstChunk ? accContent : 'No pude obtener respuesta. Por favor, inténtalo de nuevo.',
            status: 'done',
          };
        }
        return next;
      });

    } catch (err: any) {
      if (err?.name === 'AbortError') return;
      console.error('[Max] stream error:', err);
      setMessages(prev => {
        const next = [...prev];
        const last = next[next.length - 1];
        if (last && (last.role === 'thinking' || last.role === 'assistant')) {
          next[next.length - 1] = { role: 'assistant', content: 'âš ï¸ Error al conectar con PostHog. Comprueba tu configuración.', status: 'error' };
        }
        return next;
      });
    } finally {
      setIsStreaming(false);
      abortRef.current = null;
    }
  }, [conversationId, isStreaming]);

  // â”€â”€ Input submit handler â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const handleSubmit = React.useCallback((e?: React.FormEvent) => {
    e?.preventDefault();
    const text = query.trim();
    if (!text) return;
    setQuery('');
    sendMessage(text);
  }, [query, sendMessage]);

  const handleKeyDown = React.useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
    if (e.key === 'Tab' && query.trim()) {
      e.preventDefault();
      setMode('search');
      runSearch(query);
    }
    if (e.key === 'Escape') {
      if (mode !== 'idle') { setMode('idle'); setQuery(''); setSearchRes([]); }
    }
  }, [handleSubmit, mode, query, runSearch]);

  const handleQueryChange = React.useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    setQuery(val);

    if (mode === 'search') {
      if (searchTimeout.current) clearTimeout(searchTimeout.current);
      searchTimeout.current = setTimeout(() => runSearch(val), 300);
    }
  }, [mode, runSearch]);

  const stopStreaming = React.useCallback(() => {
    abortRef.current?.abort();
    setIsStreaming(false);
    setMessages(prev => {
      const next = [...prev];
      const last = next[next.length - 1];
      if (last?.status === 'loading') {
        next[next.length - 1] = { ...last, status: 'done', role: 'assistant' };
      }
      return next;
    });
  }, []);

  // â”€â”€ Pinned / recent item icon for the three columns â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const PinnedIcon = () => (
    <svg viewBox="0 0 16 16" className="w-4 h-4 text-[#e8572a] flex-shrink-0">
      <circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.5"/>
      <circle cx="8" cy="8" r="2" fill="currentColor"/>
    </svg>
  );
  const StarredIcon = () => (
    <svg viewBox="0 0 16 16" className="w-4 h-4 text-[#f59e0b] flex-shrink-0">
      <path d="M8 1.5l1.5 4H14l-3.5 2.6 1.3 4L8 9.8l-3.8 2.3 1.3-4L2 5.5h4.5z" fill="currentColor"/>
    </svg>
  );

  // â”€â”€ RENDER: AI chat mode â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  // ── Context selector helpers ───────────────────────────────────────────────────
  const activeModeLabel = AGENT_MODES.find(m => m.key === agentMode)?.label ?? 'Auto';
  const activeModeIcon  = AGENT_MODES.find(m => m.key === agentMode)?.icon;

  const copyMsg = React.useCallback((idx: number, content: string) => {
    navigator.clipboard.writeText(content).catch(() => {});
    setCopiedMsg(idx);
    setTimeout(() => setCopiedMsg(null), 1500);
  }, []);

  // ── Shared input bar (chat + idle) ────────────────────────────────────────────
  const ChatInputBar = ({ inChat = false }: { inChat?: boolean }) => (
    <div className={`${inChat ? 'px-6 pb-5 pt-3 border-t border-[#e9eae6]' : ''} flex-shrink-0`}>
      <form onSubmit={handleSubmit} className="relative bg-white border border-[#e9eae6] rounded-2xl shadow-sm hover:shadow-md transition-shadow focus-within:border-[#3b59f6] focus-within:ring-1 focus-within:ring-[#3b59f6]">
        <textarea
          ref={inputRef} rows={1} value={query}
          onChange={handleQueryChange} onKeyDown={handleKeyDown}
          placeholder={inChat ? "Pregunta de seguimiento o /comando…" : "¿En qué puedo ayudarte? / para comandos"}
          disabled={isStreaming}
          className="w-full resize-none bg-transparent px-4 pt-3.5 pb-11 pr-14 text-sm text-[#1a1a18] placeholder-[#9ca3af] focus:outline-none disabled:opacity-60"
          style={{ minHeight: 60, maxHeight: 200 }}
        />
        <div className="absolute bottom-2.5 left-3 right-3 flex items-center gap-2">
          {/* Context / agent mode selector */}
          <div className="relative">
            <button type="button" onClick={() => setShowModeMenu(v => !v)}
              className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg bg-[#f3f3f1] hover:bg-[#e9eae6] text-[#1a1a18] text-xs font-medium transition-colors">
              {activeModeIcon}
              <span>{activeModeLabel}</span>
              <svg viewBox="0 0 10 10" className="w-2.5 h-2.5 text-[#9ca3af]"><path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.2" fill="none" strokeLinecap="round"/></svg>
            </button>
            {showModeMenu && (
              <div className="absolute bottom-full left-0 mb-1.5 bg-white border border-[#e9eae6] rounded-xl shadow-xl z-50 py-1 w-52 overflow-hidden">
                {AGENT_MODES.map(m => (
                  <button key={m.key} type="button" onClick={() => { setAgentMode(m.key); setShowModeMenu(false); }}
                    className={`w-full flex items-center gap-2.5 px-3 py-2 text-sm hover:bg-[#f9f9f7] text-left transition-colors ${agentMode === m.key ? 'text-[#3b59f6] font-medium bg-[#f0f4ff]' : 'text-[#1a1a18]'}`}>
                    <span className={agentMode === m.key ? 'text-[#3b59f6]' : 'text-[#646462]'}>{m.icon}</span>
                    {m.label}
                    {agentMode === m.key && <svg viewBox="0 0 16 16" className="w-3.5 h-3.5 ml-auto text-[#3b59f6]"><path d="M3 8l3.5 3.5L13 5" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>
                ))}
              </div>
            )}
          </div>
          {/* Add context */}
          <button type="button" className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg bg-[#f3f3f1] hover:bg-[#e9eae6] text-xs text-[#646462] font-medium transition-colors">
            <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.3"/><path d="M8 5.5v5M5.5 8h5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
            Añadir contexto
          </button>
          <div className="flex-1"/>
          {/* Send / stop */}
          {isStreaming ? (
            <button type="button" onClick={stopStreaming} className="w-8 h-8 rounded-lg bg-[#fee2e2] text-[#dc2626] hover:bg-[#fecaca] transition-colors flex items-center justify-center">
              <svg viewBox="0 0 16 16" className="w-3.5 h-3.5 fill-current"><rect x="4" y="4" width="8" height="8" rx="1"/></svg>
            </button>
          ) : (
            <button type="submit" disabled={!query.trim()} className="w-8 h-8 rounded-lg bg-[#1a1a18] text-white hover:bg-[#333] disabled:opacity-30 disabled:cursor-not-allowed transition-colors flex items-center justify-center">
              <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M8 13V4M4 7.5L8 4l4 3.5" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
          )}
        </div>
      </form>
      <p className="text-[10px] text-[#9ca3af] mt-1.5 text-center">Max puede cometer errores. Verifica información importante.</p>
    </div>
  );

  if (mode === 'ai') {
    return (
      <div className="flex-1 flex flex-col bg-white min-h-0" onClick={() => setShowModeMenu(false)}>
        {/* Chat header */}
        <div className="flex items-center gap-2 px-5 py-2.5 border-b border-[#e9eae6] flex-shrink-0 min-w-0">
          <button onClick={() => { setMode('idle'); setQuery(''); }}
            className="flex items-center gap-1 text-sm text-[#646462] hover:text-[#1a1a18] transition-colors flex-shrink-0">
            <svg viewBox="0 0 16 16" className="w-4 h-4"><path d="M10 3L5 8l5 5" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>
            Inicio
          </button>
          {convTitle && (
            <>
              <svg viewBox="0 0 16 16" className="w-3 h-3 text-[#d1d5db] flex-shrink-0"><path d="M6 3l4 5-4 5" stroke="currentColor" strokeWidth="1.3" fill="none" strokeLinecap="round"/></svg>
              <span className="text-sm text-[#1a1a18] font-medium truncate min-w-0">{convTitle}</span>
            </>
          )}
          <div className="ml-auto flex items-center gap-1.5 flex-shrink-0">
            <button onClick={() => { navigator.clipboard.writeText(window.location.href).catch(() => {}); }}
              className="flex items-center gap-1.5 text-xs text-[#646462] hover:text-[#1a1a18] px-2.5 py-1.5 rounded-lg hover:bg-[#f3f3f1] transition-colors border border-[#e9eae6]">
              <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M10 3H13v3M13 3l-5.5 5.5M7 5H4a1 1 0 00-1 1v6a1 1 0 001 1h6a1 1 0 001-1v-3" stroke="currentColor" strokeWidth="1.3" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>
              Copiar enlace
            </button>
            <button onClick={() => { setMessages([]); setConvId(null); setConvTitle(''); }}
              className="text-xs text-[#646462] hover:text-[#1a1a18] px-2.5 py-1.5 rounded-lg hover:bg-[#f3f3f1] transition-colors border border-[#e9eae6]">
              + Nueva
            </button>
          </div>
        </div>

        {/* Messages — narrow centered column for an easier read */}
        <div className="flex-1 overflow-y-auto min-h-0 bg-[#f9f9f7]">
          <div className="max-w-xl mx-auto px-4 py-8 space-y-6">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center py-24 text-center">
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-[#3b59f6] to-[#6366f1] flex items-center justify-center mb-4 shadow-md">
                  <svg viewBox="0 0 24 24" className="w-6 h-6 fill-white"><path d="M12 3c1.2 0 2.3.4 3.2 1.2L19.8 9c.8.8 1.2 1.9 1.2 3.2s-.4 2.3-1.2 3.2l-4.6 4.6c-.9.8-2 1.2-3.2 1.2s-2.3-.4-3.2-1.2L4.2 15.4C3.4 14.5 3 13.4 3 12.2S3.4 9.9 4.2 9L8.8 4.2C9.7 3.4 10.8 3 12 3z"/></svg>
                </div>
                <h3 className="text-lg font-semibold text-[#1a1a18] mb-1">Max IA</h3>
                <p className="text-sm text-[#646462] max-w-xs">Hazme preguntas sobre tus datos, usuarios, experimentos o cualquier métrica de tu proyecto.</p>
              </div>
            )}
            {messages.map((msg, i) => (
              <div key={i} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                {(msg.role === 'assistant' || msg.role === 'thinking') && (
                  <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-[#3b59f6] to-[#6366f1] flex items-center justify-center flex-shrink-0 mt-0.5 shadow-sm">
                    <svg viewBox="0 0 16 16" className="w-3.5 h-3.5 fill-white"><path d="M8 2c.8 0 1.5.3 2 .8L13.2 6c.5.5.8 1.2.8 2s-.3 1.5-.8 2l-3.2 3.2c-.5.5-1.2.8-2 .8s-1.5-.3-2-.8L2.8 10C2.3 9.5 2 8.8 2 8s.3-1.5.8-2L6 2.8C6.5 2.3 7.2 2 8 2z"/></svg>
                  </div>
                )}
                <div className={`${msg.role === 'user' ? 'max-w-[80%]' : 'flex-1 min-w-0'}`}>
                  {/* User bubble */}
                  {msg.role === 'user' && (
                    <div className="bg-white border border-[#e9eae6] text-[#1a1a18] rounded-2xl rounded-tr-sm px-4 py-2.5 text-sm shadow-sm">{msg.content}</div>
                  )}
                  {/* Thinking state */}
                  {msg.role === 'thinking' && msg.status === 'loading' && (
                    <div className="flex flex-col gap-1">
                      <button type="button" onClick={() => setExpandedThoughts(s => { const n = new Set(s); n.has(i) ? n.delete(i) : n.add(i); return n; })}
                        className="flex items-center gap-1.5 text-[#9ca3af] text-xs hover:text-[#646462] transition-colors w-fit">
                        <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.3"/><path d="M6.5 6.5c0-1 .9-1.8 1.5-1.8s1.5.8 1.5 1.8-.9 1.2-1.5 1.8v.5M8 11v.5" stroke="currentColor" strokeWidth="1.1" strokeLinecap="round"/></svg>
                        Thought
                        <svg viewBox="0 0 10 10" className={`w-2.5 h-2.5 transition-transform ${expandedThoughts.has(i) ? 'rotate-90' : ''}`}><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.2" fill="none" strokeLinecap="round"/></svg>
                      </button>
                      <div className="flex items-center gap-1.5 text-[#9ca3af] text-sm pl-1">
                        <span>{thinkingMsg}</span>
                        <span className="flex gap-0.5">{[0,1,2].map(j => <span key={j} className="w-1 h-1 bg-[#c4c4be] rounded-full animate-bounce" style={{ animationDelay: `${j * 0.15}s` }}/>)}</span>
                      </div>
                    </div>
                  )}
                  {/* Assistant message */}
                  {msg.role === 'assistant' && (
                    <div className="flex flex-col gap-1.5">
                      <button type="button" onClick={() => setExpandedThoughts(s => { const n = new Set(s); n.has(i) ? n.delete(i) : n.add(i); return n; })}
                        className="flex items-center gap-1.5 text-[#9ca3af] text-xs hover:text-[#646462] transition-colors w-fit">
                        <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.3"/><path d="M6.5 6.5c0-1 .9-1.8 1.5-1.8s1.5.8 1.5 1.8-.9 1.2-1.5 1.8v.5M8 11v.5" stroke="currentColor" strokeWidth="1.1" strokeLinecap="round"/></svg>
                        Thought
                        <svg viewBox="0 0 10 10" className={`w-2.5 h-2.5 transition-transform ${expandedThoughts.has(i) ? 'rotate-90' : ''}`}><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.2" fill="none" strokeLinecap="round"/></svg>
                      </button>
                      <div className="text-sm text-[#1a1a18] leading-relaxed">
                        <div className="prose prose-sm max-w-none">
                          {renderHomeMarkdown(msg.content)}
                          {msg.status === 'loading' && <span className="inline-block w-0.5 h-4 bg-[#3b59f6] animate-pulse ml-0.5 align-text-bottom"/>}
                        </div>
                      </div>
                      {msg.status === 'done' && (
                        <div className="flex items-center gap-0.5 mt-1">
                          <button type="button" onClick={() => copyMsg(i, msg.content)}
                            className="p-1.5 rounded-lg text-[#9ca3af] hover:text-[#646462] hover:bg-[#e9eae6] transition-colors" title="Copiar">
                            {copiedMsg === i
                              ? <svg viewBox="0 0 16 16" className="w-3.5 h-3.5 text-[#16a34a]"><path d="M3 8l3.5 3.5L13 5" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>
                              : <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><rect x="5" y="5" width="8" height="9" rx="1" fill="none" stroke="currentColor" strokeWidth="1.3"/><path d="M3 11V3a1 1 0 011-1h7" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
                            }
                          </button>
                          <button type="button" onClick={() => setMsgFeedback(s => ({ ...s, [i]: s[i] === 'up' ? undefined as any : 'up' }))}
                            className={`p-1.5 rounded-lg transition-colors ${msgFeedback[i] === 'up' ? 'text-[#16a34a] bg-[#f0fdf4]' : 'text-[#9ca3af] hover:text-[#646462] hover:bg-[#e9eae6]'}`} title="Buena respuesta">
                            <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M5 14V7.5l3-5 1 .5.5 3H13l-1 7H5zM5 7.5H3a1 1 0 00-1 1V13a1 1 0 001 1h2" fill="none" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/></svg>
                          </button>
                          <button type="button" onClick={() => setMsgFeedback(s => ({ ...s, [i]: s[i] === 'down' ? undefined as any : 'down' }))}
                            className={`p-1.5 rounded-lg transition-colors ${msgFeedback[i] === 'down' ? 'text-[#dc2626] bg-[#fef2f2]' : 'text-[#9ca3af] hover:text-[#646462] hover:bg-[#e9eae6]'}`} title="Mala respuesta">
                            <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M11 2v6.5l-3 5-1-.5-.5-3H3l1-7h7zM11 8.5h2a1 1 0 011-1V3a1 1 0 00-1-1h-2" fill="none" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/></svg>
                          </button>
                          <button type="button" onClick={() => { const prev = messages.slice(0, i).filter(m => m.role === 'user').pop(); if (prev) sendMessage(prev.content); }}
                            className="p-1.5 rounded-lg text-[#9ca3af] hover:text-[#646462] hover:bg-[#e9eae6] transition-colors" title="Reintentar">
                            <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M13 8A5 5 0 112 8" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" fill="none"/><path d="M13 4v4h-4" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round" fill="none"/></svg>
                          </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>
                {msg.role === 'user' && (
                  <div className="w-7 h-7 rounded-full bg-[#e8572a] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-white text-xs font-bold">{username?.[0]?.toUpperCase() || 'U'}</span>
                  </div>
                )}
              </div>
            ))}
            <div ref={chatBottomRef} />
          </div>
        </div>

        {/* Input bar — matches the message column width */}
        <div className="bg-[#f9f9f7] border-t border-[#e9eae6] pb-2">
          <div className="max-w-xl mx-auto px-4 pt-3">
            <ChatInputBar inChat />
          </div>
        </div>
      </div>
    );
  }

  // â”€â”€ RENDER: Search mode â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  if (mode === 'search') {
    // Category list for left panel
    const SEARCH_CATEGORIES: { key: SearchCategory; label: string; icon: React.ReactNode }[] = [
      { key: 'all',        label: 'Todo',        icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><rect x="2" y="2" width="5" height="5" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/><rect x="9" y="2" width="5" height="5" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/><rect x="2" y="9" width="5" height="5" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/><rect x="9" y="9" width="5" height="5" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/></svg> },
      { key: 'recent',     label: 'Recientes',   icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.2"/><path d="M8 5v3l2 1.5" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/></svg> },
      { key: 'pinned',     label: 'Anclados',    icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M8 2l1.5 4.5H14l-3.5 2.5 1.5 4.5L8 11l-4 2.5 1.5-4.5L2 6.5h4.5z" fill="none" stroke="currentColor" strokeWidth="1.2" strokeLinejoin="round"/></svg> },
      { key: 'events',     label: 'Eventos',     icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><circle cx="8" cy="8" r="2.5" fill="currentColor" opacity=".7"/><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.2"/></svg> },
      { key: 'actions',    label: 'Acciones',    icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M3 8l3.5 3.5L13 5" stroke="currentColor" strokeWidth="1.4" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg> },
      { key: 'insights',   label: 'Insights',    icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M2 12l3.5-4 3 2.5L12 5l2 2" stroke="currentColor" strokeWidth="1.2" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg> },
      { key: 'dashboards', label: 'Dashboards',  icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><rect x="2" y="2" width="5.5" height="5.5" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/><rect x="8.5" y="2" width="5.5" height="2.5" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/><rect x="8.5" y="5.5" width="5.5" height="2" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/><rect x="2" y="8.5" width="12" height="5.5" rx="0.8" fill="none" stroke="currentColor" strokeWidth="1.2"/></svg> },
      { key: 'notebooks',  label: 'Notebooks',   icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><rect x="3" y="2" width="10" height="12" rx="1" fill="none" stroke="currentColor" strokeWidth="1.2"/><path d="M6 5h4M6 8h4M6 11h2" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/></svg> },
      { key: 'issues',     label: 'Problemas',   icon: <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M8 3v5M8 11v1.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/><path d="M2.5 13.5l5.5-11 5.5 11H2.5z" fill="none" stroke="currentColor" strokeWidth="1.2" strokeLinejoin="round"/></svg> },
    ];

    // Filter results by selected category
    const catResults = searchCategory === 'all'
      ? searchResults
      : searchResults.filter(r => r.type === searchCategory);

    // Group results by type for the "all" view
    const grouped: Record<string, typeof searchResults> = {};
    for (const r of catResults) {
      if (!grouped[r.type]) grouped[r.type] = [];
      grouped[r.type].push(r);
    }

    return (
      <div className="flex-1 flex flex-col bg-white min-h-0">
        {/* Search header */}
        <div className="px-5 pt-4 pb-3 flex-shrink-0 border-b border-[#f3f3f1]">
          <div className="relative">
            <svg viewBox="0 0 16 16" className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-[#9ca3af]"><circle cx="7" cy="7" r="4.5" fill="none" stroke="currentColor" strokeWidth="1.4"/><path d="M10.5 10.5l2.5 2.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
            <input
              autoFocus
              value={query}
              onChange={e => { setQuery(e.target.value); runSearch(e.target.value); }}
              onKeyDown={e => { if (e.key === 'Escape') { setMode('idle'); setQuery(''); setSearchRes([]); setSearchCategory('all'); } }}
              className="w-full pl-9 pr-9 py-2 border border-[#e9eae6] rounded-lg text-sm bg-[#f9f9f7] focus:outline-none focus:border-[#3b59f6] focus:bg-white text-[#1a1a18] transition-colors"
              placeholder="Buscar dashboards, insights, feature flags, eventos..."
            />
            <button type="button" onClick={() => { setMode('idle'); setQuery(''); setSearchRes([]); setSearchCategory('all'); }}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-[#9ca3af] hover:text-[#1a1a18] transition-colors">
              <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M4 4l8 8M12 4l-8 8" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/></svg>
            </button>
          </div>
        </div>

        {/* Two-panel body */}
        <div className="flex flex-1 min-h-0">
          {/* Left: category list */}
          <div className="w-44 flex-shrink-0 border-r border-[#f3f3f1] py-3 px-2 overflow-y-auto">
            {SEARCH_CATEGORIES.map(cat => {
              const count = cat.key === 'all' ? searchResults.length : searchResults.filter(r => r.type === cat.key).length;
              const isActive = searchCategory === cat.key;
              return (
                <button
                  key={cat.key}
                  onClick={() => setSearchCategory(cat.key)}
                  className={`w-full flex items-center gap-2 px-2.5 py-1.5 rounded-lg text-sm transition-colors mb-0.5 ${isActive ? 'bg-[#f0f0ff] text-[#3b59f6] font-medium' : 'text-[#646462] hover:bg-[#f9f9f7] hover:text-[#1a1a18]'}`}
                >
                  <span className={isActive ? 'text-[#3b59f6]' : 'text-[#9ca3af]'}>{cat.icon}</span>
                  <span className="flex-1 text-left truncate">{cat.label}</span>
                  {count > 0 && (
                    <span className={`text-[10px] font-medium px-1.5 py-0.5 rounded-full ${isActive ? 'bg-[#3b59f6] text-white' : 'bg-[#f3f3f1] text-[#9ca3af]'}`}>{count}</span>
                  )}
                </button>
              );
            })}
          </div>

          {/* Right: results */}
          <div className="flex-1 overflow-y-auto py-3">
            {searchLoading ? (
              <div className="space-y-1 px-3">
                {[1,2,3,4,5].map(i => (
                  <div key={i} className="flex items-center gap-3 px-2 py-2.5">
                    <div className="w-6 h-6 bg-[#f3f3f1] rounded animate-pulse flex-shrink-0" />
                    <div className="h-4 bg-[#f3f3f1] rounded animate-pulse flex-1" style={{ maxWidth: `${50 + (i % 3) * 20}%` }} />
                    <div className="h-3 w-16 bg-[#f3f3f1] rounded animate-pulse" />
                  </div>
                ))}
              </div>
            ) : !query.trim() ? (
              /* Empty state — no query */
              <div className="flex flex-col items-center justify-center h-full px-6 text-center">
                <svg viewBox="0 0 40 40" className="w-10 h-10 text-[#e9eae6] mb-3"><circle cx="18" cy="18" r="11" fill="none" stroke="currentColor" strokeWidth="2"/><path d="M26 26l8 8" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/></svg>
                <p className="text-sm font-medium text-[#1a1a18] mb-1">Busca en tu proyecto</p>
                <p className="text-xs text-[#9ca3af]">Dashboards, insights, feature flags, eventos, notebooks y más</p>
                {/* Keyboard hints */}
                <div className="mt-6 flex flex-col gap-1.5 text-xs text-[#9ca3af]">
                  <div className="flex items-center gap-2"><kbd className="px-1.5 py-0.5 bg-[#f3f3f1] border border-[#e9eae6] rounded text-[10px] font-mono">↑↓</kbd><span>navegar</span></div>
                  <div className="flex items-center gap-2"><kbd className="px-1.5 py-0.5 bg-[#f3f3f1] border border-[#e9eae6] rounded text-[10px] font-mono">↵</kbd><span>abrir</span></div>
                  <div className="flex items-center gap-2"><kbd className="px-1.5 py-0.5 bg-[#f3f3f1] border border-[#e9eae6] rounded text-[10px] font-mono">Esc</kbd><span>cerrar</span></div>
                </div>
              </div>
            ) : catResults.length === 0 ? (
              /* No results */
              <div className="flex flex-col items-center justify-center h-full px-6 text-center">
                <svg viewBox="0 0 40 40" className="w-10 h-10 text-[#e9eae6] mb-3"><circle cx="18" cy="18" r="11" fill="none" stroke="currentColor" strokeWidth="2"/><path d="M26 26l8 8" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/></svg>
                <p className="text-sm text-[#646462]">Sin resultados para <strong className="text-[#1a1a18]">"{query}"</strong></p>
                <p className="text-xs text-[#9ca3af] mt-1">Prueba con otras palabras o cambia la categoría</p>
              </div>
            ) : (
              /* Results list — grouped when "all" */
              <div>
                {searchCategory === 'all' ? (
                  Object.entries(grouped).map(([type, items]) => (
                    <div key={type} className="mb-2">
                      <div className="px-5 py-1">
                        <span className="text-[10px] font-semibold text-[#9ca3af] uppercase tracking-widest">{type}</span>
                      </div>
                      {items.map((item, i) => (
                        <div key={i}
                          className="flex items-center gap-3 px-5 py-2 hover:bg-[#f9f9f7] cursor-pointer group transition-colors">
                          <ItemTypeIcon type={item.type} />
                          <span className="text-sm text-[#1a1a18] flex-1 truncate">{item.name}</span>
                          <svg viewBox="0 0 16 16" className="w-3.5 h-3.5 text-[#c4c4be] opacity-0 group-hover:opacity-100 flex-shrink-0"><path d="M6 3l4 5-4 5" stroke="currentColor" strokeWidth="1.3" fill="none" strokeLinecap="round"/></svg>
                        </div>
                      ))}
                    </div>
                  ))
                ) : (
                  catResults.map((item, i) => (
                    <div key={i}
                      className="flex items-center gap-3 px-5 py-2 hover:bg-[#f9f9f7] cursor-pointer group transition-colors">
                      <ItemTypeIcon type={item.type} />
                      <span className="text-sm text-[#1a1a18] flex-1 truncate">{item.name}</span>
                      <svg viewBox="0 0 16 16" className="w-3.5 h-3.5 text-[#c4c4be] opacity-0 group-hover:opacity-100 flex-shrink-0"><path d="M6 3l4 5-4 5" stroke="currentColor" strokeWidth="1.3" fill="none" strokeLinecap="round"/></svg>
                    </div>
                  ))
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  // â”€â”€ RENDER: Idle (main homepage) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  return (
    <div className="flex-1 flex flex-col bg-[#f9f9f7] min-h-0 overflow-y-auto">
      <div className="flex flex-col items-center justify-center flex-1 min-h-0 px-6 py-12">

        {/* Project icon */}
        <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-[#3b59f6] to-[#6366f1] flex items-center justify-center mb-5 shadow-lg">
          <svg viewBox="0 0 24 24" className="w-8 h-8 fill-white"><path d="M5 3h14a2 2 0 012 2v9a2 2 0 01-2 2H9l-4 4V5a2 2 0 012-2z"/><path d="M9 9h6M9 12h4" stroke="white" strokeWidth="1.5" strokeLinecap="round" fill="none"/></svg>
        </div>

        {/* Greeting + Inicio rápido button */}
        {dataLoading ? (
          <div className="h-9 w-48 bg-[#e9eae6] rounded-lg animate-pulse mb-7" />
        ) : (
          <div className="flex items-center gap-3 mb-7">
            <h1 className="text-3xl font-semibold text-[#1a1a18]">
              Hola, {username || 'usuario'} <span aria-label="saludando">👋</span>
            </h1>
            <button
              onClick={() => setShowQuickStart(true)}
              className="flex items-center gap-1.5 px-2.5 py-1 bg-white border border-[#e9eae6] rounded-md text-xs text-[#1a1a18] hover:bg-[#f9f9f7] shadow-sm transition-colors"
              title="Plantillas rápidas para empezar"
            >
              <svg viewBox="0 0 16 16" className="w-3 h-3 text-[#646462]"><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.3"/><path d="M8 5v3l2 1.5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
              Inicio rápido
              <span className="bg-[#f59e0b] text-white text-[9px] font-bold px-1.5 py-0.5 rounded-full">ON</span>
            </button>
          </div>
        )}

        {/* Input — Home keeps the wider input for landing UX */}
        <div className="w-full max-w-2xl">
          <ChatInputBar />
        </div>

        {/* Three columns */}
        {!dataLoading && (widgets.pinned || widgets.recents || widgets.starred) && (
          <div className={`w-full max-w-2xl mt-10 grid gap-8 ${[widgets.pinned, widgets.recents, widgets.starred].filter(Boolean).length === 3 ? 'grid-cols-3' : [widgets.pinned, widgets.recents, widgets.starred].filter(Boolean).length === 2 ? 'grid-cols-2' : 'grid-cols-1'}`}>
            {/* Pinned */}
            {widgets.pinned && (
              <div>
                <div className="flex items-center gap-1.5 mb-3">
                  <PinnedIcon />
                  <span className="text-[10px] font-semibold text-[#9ca3af] uppercase tracking-widest">Paneles anclados</span>
                </div>
                {pinned.length === 0 ? (
                  <p className="text-xs text-[#c4c4be] italic">No hay paneles anclados</p>
                ) : (
                  <div className="space-y-1.5">
                    {pinned.map((p, i) => (
                      <button key={i} onClick={() => navigateWA('appDashboards', { kind: 'dashboard', id: p.id })} className="w-full flex items-center gap-2 text-sm text-[#3b59f6] hover:text-[#2a44d6] cursor-pointer hover:underline truncate text-left">
                        <PinnedIcon />
                        <span className="truncate">{p.name}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Recent */}
            {widgets.recents && (
              <div>
                <div className="flex items-center gap-1.5 mb-3">
                  <svg viewBox="0 0 16 16" className="w-4 h-4 text-[#9ca3af] flex-shrink-0"><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.3"/><path d="M8 5v3l2 1.5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
                  <span className="text-[10px] font-semibold text-[#9ca3af] uppercase tracking-widest">Recientes</span>
                </div>
                {recents.length === 0 ? (
                  <p className="text-xs text-[#c4c4be] italic">Sin actividad reciente</p>
                ) : (
                  <div className="space-y-1.5">
                    {recents.map((r, i) => (
                      <button key={i} onClick={() => navigateWA('appProductAnalytics', { kind: 'insight', id: r.id })} className="w-full flex items-center gap-2 text-sm text-[#3b59f6] hover:text-[#2a44d6] cursor-pointer hover:underline truncate text-left">
                        <ItemTypeIcon type={r.type} />
                        <span className="truncate">{r.name}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Starred */}
            {widgets.starred && (
              <div>
                <div className="flex items-center gap-1.5 mb-3">
                  <StarredIcon />
                  <span className="text-[10px] font-semibold text-[#9ca3af] uppercase tracking-widest">Destacados</span>
                </div>
                {starred.length === 0 ? (
                  <p className="text-xs text-[#c4c4be] italic">No hay elementos destacados</p>
                ) : (
                  <div className="space-y-1.5">
                    {starred.map((s, i) => (
                      <button key={i} onClick={() => navigateWA('appDashboards', { kind: 'dashboard', id: s.id })} className="w-full flex items-center gap-2 text-sm text-[#f59e0b] hover:text-[#d97706] cursor-pointer hover:underline truncate text-left">
                        <StarredIcon />
                        <span className="text-[#3b59f6] hover:text-[#2a44d6] truncate">{s.name}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {/* Activity stream widget — uses same backend as Activity view */}
        {!dataLoading && widgets.activity && (
          <div className="w-full max-w-2xl mt-10 border-t border-[#e9eae6] pt-6">
            <div className="flex items-center gap-1.5 mb-3">
              <svg viewBox="0 0 16 16" className="w-4 h-4 text-[#9ca3af]"><path d="M2 10c2-4 5-6 6-6s4 2 6 6" stroke="currentColor" strokeWidth="1.3" fill="none" strokeLinecap="round"/><circle cx="8" cy="11.5" r="1.5" fill="currentColor"/></svg>
              <span className="text-[10px] font-semibold text-[#9ca3af] uppercase tracking-widest">Actividad reciente (última hora)</span>
              <span className="ml-auto inline-flex items-center gap-1 text-[10px] text-[#16a34a]">
                <span className="w-1.5 h-1.5 bg-[#16a34a] rounded-full animate-pulse" />
                EN VIVO
              </span>
            </div>
            {eventsLoading ? (
              <div className="space-y-2">
                {[0,1,2,3,4].map(i => <div key={i} className="h-8 bg-[#f3f3f1] rounded animate-pulse" style={{ width: `${70 + (i % 3) * 10}%` }} />)}
              </div>
            ) : recentEvents.length === 0 ? (
              <p className="text-xs text-[#c4c4be] italic py-2">Aún no hay eventos en la última hora</p>
            ) : (
              <div className="border border-[#e9eae6] rounded-lg overflow-hidden bg-white">
                {recentEvents.map((e, i) => (
                  <div
                    key={e.uuid ?? i}
                    onClick={() => setSelectedEvent(e)}
                    className={`flex items-center gap-3 px-3 py-2 text-xs cursor-pointer hover:bg-[#f9f9f7] ${i < recentEvents.length - 1 ? 'border-b border-[#f3f3f1]' : ''}`}
                  >
                    <span className="font-mono text-[#3b59f6] flex-shrink-0 w-32 truncate">{e.event}</span>
                    <span className="text-[#646462] flex-1 truncate">{e.properties?.$current_url ?? e.distinct_id}</span>
                    <span className="text-[#9ca3af] flex-shrink-0">{formatRelativeTime(e.timestamp)}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {dataLoading && (
          <div className="w-full max-w-2xl mt-10 grid grid-cols-3 gap-8">
            {[0,1,2].map(i => (
              <div key={i} className="space-y-2">
                <div className="h-3 w-24 bg-[#e9eae6] rounded animate-pulse" />
                {[0,1,2].map(j => <div key={j} className="h-4 bg-[#e9eae6] rounded animate-pulse" style={{ width: `${70 + j * 10}%` }} />)}
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Bottom bar */}
      <div className="flex items-center justify-center gap-3 py-3 px-6 bg-white border-t border-[#e9eae6] flex-shrink-0">
        <button onClick={() => setShowConfig(true)} className="flex items-center gap-1.5 text-xs text-[#646462] hover:text-[#1a1a18] px-3 py-1.5 rounded-lg hover:bg-[#f3f3f1] transition-colors">
          <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><circle cx="8" cy="8" r="5.5" fill="none" stroke="currentColor" strokeWidth="1.3"/><path d="M8 5.5v2.5l1.5 1" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
          Configurar inicio
        </button>
        <button onClick={() => setWidgets(DEFAULT_WIDGETS)} className="flex items-center gap-1.5 text-xs text-[#646462] hover:text-[#1a1a18] px-3 py-1.5 rounded-lg hover:bg-[#f3f3f1] transition-colors">
          <svg viewBox="0 0 16 16" className="w-3.5 h-3.5"><path d="M13 8A5 5 0 112 8" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" fill="none"/><path d="M13 4v4h-4" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round" fill="none"/></svg>
          Restaurar panel predeterminado
        </button>
      </div>

      {/* Shared modals — reused from Activity view */}
      <QuickStartPanel
        open={showQuickStart}
        onClose={() => setShowQuickStart(false)}
        onPickRecipe={() => { setShowQuickStart(false); }}
      />
      <EventDetailDrawer row={selectedEvent} onClose={() => setSelectedEvent(null)} />

      {/* Configurar inicio — widget visibility */}
      {showConfig && (
        <div className="fixed inset-0 bg-[#1a1a18]/30 z-50 flex items-center justify-center" onClick={() => setShowConfig(false)}>
          <div onClick={e => e.stopPropagation()} className="bg-white rounded-2xl shadow-2xl w-[440px] max-w-[92vw] overflow-hidden">
            <div className="px-5 py-4 border-b border-[#e9eae6] flex items-center justify-between">
              <div>
                <h2 className="text-base font-bold text-[#1a1a18]">Configurar inicio</h2>
                <p className="text-xs text-[#646462] mt-0.5">Elige qué widgets ver en tu página principal.</p>
              </div>
              <button onClick={() => setShowConfig(false)} className="text-[#9ca3af] hover:text-[#1a1a18]">
                <svg viewBox="0 0 16 16" className="w-4 h-4"><path d="M4 4l8 8M12 4l-8 8" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/></svg>
              </button>
            </div>
            <div className="p-4 space-y-2">
              {[
                { key: 'pinned',   label: 'Paneles anclados',  desc: 'Dashboards marcados como anclados.' },
                { key: 'recents',  label: 'Recientes',         desc: 'Últimos insights vistos.' },
                { key: 'starred',  label: 'Destacados',        desc: 'Elementos marcados con estrella.' },
                { key: 'activity', label: 'Actividad reciente', desc: 'Últimos eventos de la última hora.' },
              ].map(w => (
                <label key={w.key} className="flex items-start gap-3 p-3 border border-[#e9eae6] rounded-lg cursor-pointer hover:bg-[#f9f9f7]">
                  <input
                    type="checkbox"
                    checked={(widgets as any)[w.key]}
                    onChange={e => setWidgets(prev => ({ ...prev, [w.key]: e.target.checked }))}
                    className="mt-0.5 accent-[#3b59f6]"
                  />
                  <div className="flex-1">
                    <p className="text-sm font-medium text-[#1a1a18]">{w.label}</p>
                    <p className="text-xs text-[#646462] mt-0.5">{w.desc}</p>
                  </div>
                </label>
              ))}
            </div>
            <div className="px-5 py-3 border-t border-[#e9eae6] flex justify-between">
              <button onClick={() => setWidgets(DEFAULT_WIDGETS)} className="text-xs text-[#646462] hover:text-[#1a1a18]">Restaurar predeterminado</button>
              <button onClick={() => setShowConfig(false)} className="px-3 py-1.5 bg-[#1a1a18] text-white text-xs rounded-lg hover:bg-[#333]">Hecho</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}



// ── WADataSidebar — identical pattern to ReportsSidebar / KnowledgeSidebar ──
