          <svg viewBox="0 0 16 16" className="w-4 h-4 fill-none stroke-[#1a1a1a] flex-shrink-0" strokeWidth="1.5"><path d="M3 4h10M3 8h7M3 12h5" strokeLinecap="round"/></svg>
